import asyncio
import json
import uuid
from dataclasses import asdict
from typing import Dict

from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from sse_starlette.sse import EventSourceResponse

from . import agent, embedder, ingestion
from . import parser as code_parser

app = FastAPI(title="archaeologist")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

REPORTS: Dict[str, dict] = {}


class AnalyzeRequest(BaseModel):
    github_url: str


async def _run_pipeline(github_url: str, job_id: str):
    yield {"event": "job_id", "data": job_id}

    yield {"event": "progress", "data": "Cloning repo..."}
    manifest = await asyncio.to_thread(ingestion.clone_and_manifest, github_url)

    yield {"event": "progress", "data": f"Parsing {manifest['file_count']} files..."}
    parse_result = await asyncio.to_thread(code_parser.parse_manifest, manifest)

    yield {"event": "progress", "data": "Embedding chunks..."}
    await asyncio.to_thread(embedder.build_index, parse_result.chunks)

    yield {"event": "progress", "data": "Running analysis..."}
    report = await asyncio.to_thread(
        agent.generate_report, parse_result.symbol_map, manifest["temp_dir"]
    )

    report_dict = asdict(report)
    REPORTS[job_id] = report_dict
    yield {"event": "done", "data": json.dumps(report_dict)}


@app.post("/analyze")
async def analyze(req: AnalyzeRequest):
    job_id = str(uuid.uuid4())
    return EventSourceResponse(_run_pipeline(req.github_url, job_id))


@app.get("/report/{job_id}")
async def get_report(job_id: str):
    if job_id not in REPORTS:
        raise HTTPException(status_code=404, detail="report not found")
    return REPORTS[job_id]

import os
import tempfile
from pathlib import Path
from git import Repo

EXCLUDE_SEGMENTS = ("__pycache__", "venv", ".git", "node_modules", "/test")


def _should_skip(path: str) -> bool:
    return any(segment in Path(path).parts for segment in EXCLUDE_SEGMENTS)


def clone_and_manifest(github_url: str) -> dict:
    repo_name = github_url.rstrip("/").split("/")[-1].removesuffix(".git")
    temp_dir = tempfile.mkdtemp(prefix=f"archaeologist_{repo_name}_")

    Repo.clone_from(github_url, temp_dir, depth=1)

    files = []
    for root, dirs, filenames in os.walk(temp_dir):
        dirs[:] = [d for d in dirs if not _should_skip(os.path.join(root, d))]
        for name in filenames:
            if not name.endswith(".py"):
                continue
            full_path = os.path.join(root, name)
            if _should_skip(full_path):
                continue
            files.append(os.path.abspath(full_path))
    print(f"Found {len(files)} .py files: {files[:5]}")

    return {
        "repo_name": repo_name,
        "temp_dir": temp_dir,
        "files": files,
        "file_count": len(files),
    }

from dataclasses import dataclass, field
from typing import Dict, List

import tree_sitter_python
from tree_sitter import Language, Node, Parser

_LANGUAGE = Language(tree_sitter_python.language())
_PARSER = Parser(_LANGUAGE)


@dataclass
class ParseResult:
    chunks: List[dict] = field(default_factory=list)
    symbol_map: Dict[str, List[str]] = field(default_factory=dict)


def _text(node: Node, source: bytes) -> str:
    return source[node.start_byte:node.end_byte].decode("utf-8", errors="replace")


def _extract_docstring(definition: Node, source: bytes) -> str | None:
    body = definition.child_by_field_name("body")
    if body is None:
        return None
    for child in body.named_children:
        if child.type == "expression_statement":
            inner = child.named_children[0] if child.named_children else None
            if inner is not None and inner.type == "string":
                raw = _text(inner, source)
                return raw.strip().strip("'\"")
        return None
    return None


def _dotted_name(node: Node, source: bytes) -> str:
    return _text(node, source)


def _record_import(symbol_map: Dict[str, List[str]], module: str, name: str) -> None:
    symbol_map.setdefault(module, []).append(name)


def _handle_import_statement(node: Node, source: bytes, symbol_map: Dict[str, List[str]]) -> None:
    for child in node.named_children:
        if child.type == "dotted_name":
            module = _dotted_name(child, source)
            _record_import(symbol_map, module, module)
        elif child.type == "aliased_import":
            name_node = child.child_by_field_name("name")
            alias_node = child.child_by_field_name("alias")
            if name_node is None:
                continue
            module = _dotted_name(name_node, source)
            alias = _text(alias_node, source) if alias_node is not None else module
            _record_import(symbol_map, module, alias)


def _handle_import_from_statement(node: Node, source: bytes, symbol_map: Dict[str, List[str]]) -> None:
    module_node = node.child_by_field_name("module_name")
    module = _dotted_name(module_node, source) if module_node is not None else ""

    for child in node.named_children:
        if child == module_node:
            continue
        if child.type == "dotted_name":
            _record_import(symbol_map, module, _dotted_name(child, source))
        elif child.type == "aliased_import":
            name_node = child.child_by_field_name("name")
            alias_node = child.child_by_field_name("alias")
            if name_node is None:
                continue
            imported = _text(alias_node, source) if alias_node is not None else _dotted_name(name_node, source)
            _record_import(symbol_map, module, imported)
        elif child.type == "wildcard_import":
            _record_import(symbol_map, module, "*")


def _parse_file(file_path: str, result: ParseResult) -> None:
    with open(file_path, "rb") as f:
        source = f.read()

    tree = _PARSER.parse(source)
    root = tree.root_node

    for node in root.named_children:
        if node.type in ("function_definition", "class_definition"):
            name_node = node.child_by_field_name("name")
            if name_node is None:
                continue
            result.chunks.append({
                "name": _text(name_node, source),
                "kind": "function" if node.type == "function_definition" else "class",
                "docstring": _extract_docstring(node, source),
                "source": _text(node, source),
                "file_path": file_path,
            })
        elif node.type == "import_statement":
            _handle_import_statement(node, source, result.symbol_map)
        elif node.type == "import_from_statement":
            _handle_import_from_statement(node, source, result.symbol_map)


def parse_manifest(manifest: dict) -> ParseResult:
    result = ParseResult()
    for file_path in manifest["files"]:
        try:
            _parse_file(file_path, result)
        except (OSError, UnicodeDecodeError):
            continue
    return result

import os
import re
import sys
from dataclasses import asdict, dataclass, field
from typing import List

from langchain_core.prompts import ChatPromptTemplate
from langchain_openai import ChatOpenAI
from pydantic import BaseModel

from . import embedder

LLM = ChatOpenAI(model="gpt-4o-mini", temperature=0)

INCOMPLETE_MARKERS = ("TODO", "FIXME", "NotImplemented", "raise NotImplementedError")

_PASS_STUB_RE = re.compile(
    r'^\s*(?:async\s+)?def\s+\w+\([^)]*\)\s*(?:->[^:]+)?:\s*\n'
    r'(?:\s*(?:"""(?:.|\n)*?"""|\'\'\'(?:.|\n)*?\'\'\')\s*\n)?'
    r'\s*pass\s*$',
    re.MULTILINE,
)


class PurposeOutput(BaseModel):
    purpose: str
    one_liner: str


class ModuleSummary(BaseModel):
    name: str
    description: str


class ArchitectureOutput(BaseModel):
    modules: List[ModuleSummary]


class IncompleteOutput(BaseModel):
    incomplete_features: List[str]


@dataclass
class ReportJSON:
    purpose: str
    one_liner: str
    modules: List[dict] = field(default_factory=list)
    incomplete_features: List[str] = field(default_factory=list)
    dependency_graph: str = ""


_STDLIB_PREFIXES = set(getattr(sys, "stdlib_module_names", set())) | {
    "__future__", "builtins",
}

_THIRD_PARTY_PREFIXES = {
    "anyio", "attr", "attrs", "boto3", "botocore", "certifi", "click",
    "dotenv", "faiss", "fastapi", "git", "h11", "httpx", "httpcore",
    "jinja2", "jiter", "jsonpatch", "jsonpointer", "langchain",
    "langchain_core", "langchain_openai", "langgraph", "langsmith",
    "markdown", "markupsafe", "numpy", "openai", "orjson", "ormsgpack",
    "packaging", "pallets_sphinx_themes", "pandas", "pluggy", "pydantic",
    "pydantic_core", "pytest", "regex", "requests", "rich", "smmap",
    "sniffio", "sphinx", "sphinxcontrib", "sqlalchemy", "sse_starlette",
    "starlette", "tenacity", "tiktoken", "tornado", "tqdm",
    "tree_sitter", "tree_sitter_python", "uvicorn", "websockets", "werkzeug",
    "yaml", "pyyaml",
}

_EXTERNAL_PREFIXES = _STDLIB_PREFIXES | _THIRD_PARTY_PREFIXES

_MAX_NODES = 20


def _is_internal_module(name: str) -> bool:
    if not name:
        return False
    if name.startswith("."):
        return True
    return name.split(".")[0] not in _EXTERNAL_PREFIXES


def _normalize_module(name: str) -> str:
    return name.lstrip(".") or name


def _mermaid_id(name: str) -> str:
    return "n_" + re.sub(r"[^A-Za-z0-9_]", "_", name)


def build_mermaid_graph(symbol_map: dict) -> str:
    internal = sorted({
        _normalize_module(m)
        for m in symbol_map.keys()
        if _is_internal_module(m) and _normalize_module(m)
    })

    truncated = False
    if len(internal) > _MAX_NODES:
        internal = internal[:_MAX_NODES]
        truncated = True

    internal_set = set(internal)
    edges: List[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for module in internal:
        parts = module.split(".")
        for i in range(1, len(parts)):
            parent = ".".join(parts[:i])
            if parent in internal_set:
                edge = (parent, module)
                if edge not in seen:
                    edges.append(edge)
                    seen.add(edge)

    lines = ["graph LR"]
    declared: set[str] = set()
    for src, dst in edges:
        if src not in declared:
            lines.append(f'    {_mermaid_id(src)}["{src}"]')
            declared.add(src)
        if dst not in declared:
            lines.append(f'    {_mermaid_id(dst)}["{dst}"]')
            declared.add(dst)
        lines.append(f"    {_mermaid_id(src)} --> {_mermaid_id(dst)}")
    for module in internal:
        if module not in declared:
            lines.append(f'    {_mermaid_id(module)}["{module}"]')
            declared.add(module)

    if truncated:
        lines.append(f'    %% truncated to {_MAX_NODES} nodes')

    graph_string = "\n".join(lines)
    print(f"symbol_map: {symbol_map}")
    print(f"mermaid output: {graph_string}")
    return graph_string


def _format_chunks(chunks: List[dict], root: str | None = None) -> str:
    return "\n\n---\n\n".join(
        f"# {_rel_path(c.get('file_path', ''), root)} :: {c.get('kind')} {c.get('name')}\n{c.get('source', '')}"
        for c in chunks
    )


def _rel_path(file_path: str, root: str | None) -> str:
    if not file_path:
        return ""
    if root:
        try:
            return os.path.relpath(file_path, root)
        except ValueError:
            return file_path
    return file_path


def _is_stub(chunk: dict) -> bool:
    src = chunk.get("source", "")
    if any(marker in src for marker in INCOMPLETE_MARKERS):
        return True
    if chunk.get("kind") == "function" and _PASS_STUB_RE.search(src):
        return True
    return False


def _chunks_for_file(file_path: str, limit: int = 3) -> List[dict]:
    matches = [c for c in embedder._chunks if c.get("file_path") == file_path]
    return matches[:limit]


def _purpose_step(root: str | None) -> tuple[List[dict], PurposeOutput]:
    chunks = embedder.retrieve("what does this project do", k=10)
    prompt = ChatPromptTemplate.from_messages([
        ("system", "You are analyzing a codebase. Infer the project's purpose from representative chunks."),
        ("human",
         "Representative code chunks:\n\n{chunks}\n\n"
         "Return `purpose` (1-3 sentences) and `one_liner` (≤15 words)."),
    ])
    result = (prompt | LLM.with_structured_output(PurposeOutput)).invoke(
        {"chunks": _format_chunks(chunks, root)}
    )
    return chunks, result


def _architecture_step(seed_chunks: List[dict], root: str | None) -> ArchitectureOutput:
    unique_files = list(dict.fromkeys(c["file_path"] for c in seed_chunks))
    per_file: List[tuple[str, List[dict]]] = [
        (fp, _chunks_for_file(fp, 3)) for fp in unique_files
    ]

    blocks = []
    for file_path, chunks in per_file:
        if not chunks:
            continue
        blocks.append(f"## {_rel_path(file_path, root)}\n{_format_chunks(chunks, root)}")
    joined = "\n\n===\n\n".join(blocks)

    prompt = ChatPromptTemplate.from_messages([
        ("system", "Summarize each Python module in one sentence based on its representative chunks."),
        ("human",
         "Per-module chunks:\n\n{blocks}\n\n"
         "For each module, return `name` (the relative file path exactly as shown) "
         "and `description` (one sentence)."),
    ])
    return (prompt | LLM.with_structured_output(ArchitectureOutput)).invoke({"blocks": joined})


def _incomplete_step(root: str | None) -> IncompleteOutput:
    matches = [c for c in embedder._chunks if _is_stub(c)]
    if not matches:
        return IncompleteOutput(incomplete_features=[])

    prompt = ChatPromptTemplate.from_messages([
        ("system",
         "You receive code chunks that look incomplete (TODO/FIXME/NotImplementedError/empty pass bodies). "
         "Describe each as a short, user-readable feature gap."),
        ("human",
         "Suspect chunks:\n\n{chunks}\n\n"
         "Return `incomplete_features` as a list of short strings, one per gap."),
    ])
    return (prompt | LLM.with_structured_output(IncompleteOutput)).invoke(
        {"chunks": _format_chunks(matches, root)}
    )


def generate_report(symbol_map: dict | None = None, root: str | None = None) -> ReportJSON:
    seed_chunks, purpose = _purpose_step(root)
    architecture = _architecture_step(seed_chunks, root)
    incomplete = _incomplete_step(root)
    dependency_graph = build_mermaid_graph(symbol_map or {})

    return ReportJSON(
        purpose=purpose.purpose,
        one_liner=purpose.one_liner,
        modules=[asdict(m) if hasattr(m, "__dataclass_fields__") else m.model_dump()
                 for m in architecture.modules],
        incomplete_features=list(incomplete.incomplete_features),
        dependency_graph=dependency_graph,
    )

import { useState } from 'react'
import ProgressLog from './ProgressLog.jsx'
import ReportView from './ReportView.jsx'
import styles from './App.module.css'

const BACKEND = import.meta.env.VITE_BACKEND_URL || 'http://localhost:8000'

export default function App() {
  const [url, setUrl] = useState('')
  const [status, setStatus] = useState('idle')
  const [jobId, setJobId] = useState(null)
  const [progress, setProgress] = useState([])
  const [report, setReport] = useState(null)
  const [error, setError] = useState(null)

  async function onSubmit(e) {
    e.preventDefault()
    if (!url.trim() || status === 'running') return
    setStatus('running')
    setJobId(null)
    setProgress([])
    setReport(null)
    setError(null)

    try {
      const res = await fetch(`${BACKEND}/analyze`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Accept: 'text/event-stream' },
        body: JSON.stringify({ github_url: url.trim() }),
      })
      if (!res.ok || !res.body) throw new Error(`backend responded ${res.status}`)

      const reader = res.body.getReader()
      const decoder = new TextDecoder()
      let buffer = ''

      while (true) {
        const { value, done } = await reader.read()
        if (done) break
        const chunk = decoder.decode(value, { stream: true })
        console.log('[SSE chunk]', JSON.stringify(chunk))
        buffer += chunk
        const blocks = buffer.split('\r\n\r\n')
        buffer = blocks.pop() ?? ''
        for (const block of blocks) {
          if (!block.trim()) continue
          let eventType = null
          for (const line of block.split('\r\n')) {
            if (line.startsWith('event: ')) {
              eventType = line.slice(7).trim()
            } else if (line.startsWith('data: ')) {
              const data = line.slice(6).trim()
              if (eventType === 'job_id') setJobId(data)
              if (eventType === 'progress') setProgress(prev => [...prev, data])
              if (eventType === 'done') setReport(JSON.parse(data))
              eventType = null
            }
          }
        }
      }
      setStatus('done')
    } catch (err) {
      setError(err.message || String(err))
      setStatus('error')
    }
  }

  return (
    <div className={styles.app}>
      <header className={styles.header}>
        <h1>archaeologist</h1>
        <p className={styles.subtitle}>Dig through a GitHub repo.</p>
      </header>

      <form className={styles.form} onSubmit={onSubmit}>
        <input
          className={styles.input}
          type="url"
          placeholder="https://github.com/owner/repo"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          disabled={status === 'running'}
          required
        />
        <button
          className={styles.button}
          type="submit"
          disabled={status === 'running' || !url.trim()}
        >
          {status === 'running' ? 'Analyzing…' : 'Analyze'}
        </button>
      </form>

      {jobId && (
        <p className={styles.jobId}>
          job <code>{jobId}</code>
        </p>
      )}

      {progress.length > 0 && <ProgressLog events={progress} />}

      {error && <p className={styles.error}>error: {error}</p>}

      {report && <ReportView report={report} repoUrl={url} />}
    </div>
  )
}

import { useEffect, useId, useRef, useState } from 'react'
import mermaid from 'mermaid'
import styles from './ReportView.module.css'

mermaid.initialize({ startOnLoad: false, theme: 'default', securityLevel: 'loose' })

function MermaidDiagram({ code }) {
  const baseId = useId().replace(/:/g, '_')
  const containerRef = useRef(null)
  const [error, setError] = useState(null)

  useEffect(() => {
    let cancelled = false
    if (!code?.trim()) {
      if (containerRef.current) containerRef.current.innerHTML = ''
      return
    }
    setError(null)
    mermaid
      .render(`mmd_${baseId}_${Date.now()}`, code)
      .then(({ svg }) => {
        if (!cancelled && containerRef.current) containerRef.current.innerHTML = svg
      })
      .catch((err) => {
        if (!cancelled) setError(err.message || String(err))
      })
    return () => {
      cancelled = true
    }
  }, [code, baseId])

  if (error) {
    return (
      <div className={styles.mermaidError}>
        <p>Failed to render diagram: {error}</p>
        <pre>{code}</pre>
      </div>
    )
  }
  return <div ref={containerRef} className={styles.mermaid} />
}

function repoNameFromUrl(url) {
  if (!url) return ''
  try {
    const parts = url.replace(/\.git$/, '').replace(/\/$/, '').split('/')
    return parts[parts.length - 1] || url
  } catch {
    return url
  }
}

export default function ReportView({ report, repoUrl }) {
  const repoName = repoNameFromUrl(repoUrl)
  const modules = report.modules || []
  const incomplete = report.incomplete_features || []
  const graph = report.dependency_graph || ''

  return (
    <article className={styles.report}>
      <header className={styles.head}>
        <h2 className={styles.repoName}>{repoName || 'report'}</h2>
        <p className={styles.oneLiner}>{report.one_liner}</p>
      </header>

      <section className={styles.section}>
        <h3 className={styles.sectionTitle}>Purpose</h3>
        <p className={styles.purpose}>{report.purpose}</p>
      </section>

      <section className={styles.section}>
        <h3 className={styles.sectionTitle}>Modules</h3>
        {modules.length === 0 ? (
          <p className={styles.empty}>No modules summarized.</p>
        ) : (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Description</th>
              </tr>
            </thead>
            <tbody>
              {modules.map((m, i) => (
                <tr key={i}>
                  <td className={styles.modName}>{m.name}</td>
                  <td>{m.description}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </section>

      <section className={styles.section}>
        <h3 className={styles.sectionTitle}>Dependency graph</h3>
        {graph.trim() ? (
          <MermaidDiagram code={graph} />
        ) : (
          <p className={styles.empty}>No internal dependencies detected.</p>
        )}
      </section>

      <section className={styles.section}>
        <h3 className={styles.sectionTitle}>Unfinished work</h3>
        {incomplete.length === 0 ? (
          <p className={styles.empty}>Nothing flagged.</p>
        ) : (
          <ul className={styles.todoList}>
            {incomplete.map((item, i) => (
              <li key={i}>{item}</li>
            ))}
          </ul>
        )}
      </section>
    </article>
  )
}

import { useEffect, useRef } from 'react'
import styles from './ProgressLog.module.css'

export default function ProgressLog({ events }) {
  const endRef = useRef(null)

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' })
  }, [events.length])

  return (
    <div className={styles.log} role="log" aria-live="polite">
      <ul className={styles.list}>
        {events.map((line, i) => (
          <li key={i} className={styles.item}>
            <span className={styles.bullet}>›</span>
            <span>{line}</span>
          </li>
        ))}
      </ul>
      <div ref={endRef} />
    </div>
  )
}
